      headers: { apikey: REELS_SB_KEY, Authorization: 'Bearer ' + REELS_SB_KEY }
    }).then(function (r) {
      if (!r.ok) throw new Error('HTTP ' + r.status + ' for ' + path.split('?')[0]);
      return r.json();
    });
  }

  function normalizeReelFingerprint(url) {
    try { var u = new URL(url); return (u.origin + u.pathname).toLowerCase(); } catch (e) { return String(url || '').split('?')[0].toLowerCase(); }
  }

  function isValidReel(row, publishedProjectIds) {
    if (!row || typeof row !== 'object') return false;
    var videoUrl = String(row.video_url || row.storage_path || '');
    if (!VIDEO_URL_RE.test(videoUrl)) return false;
    var visibility = String(row.visibility || 'public').toLowerCase();
    if (visibility !== 'public' && visibility !== 'global') return false;
    if (row.published === false) return false;
    if (row.is_approved === false) return false;
    var projectId = String(row.project_id || '');
    var isGlobal = row.is_global === true || visibility === 'global';
    if (!isGlobal && publishedProjectIds.indexOf(projectId) === -1) return false;
    return true;
  }

  function renderReels(reels, projectTitles) {
    var track = document.getElementById('reels-track');
    var empty = document.getElementById('reels-empty-state');
    var badge = document.getElementById('reels-count-badge');
    var countEl = document.getElementById('reels-live-count');
    if (!track || !empty) return;
    if (reels.length === 0) {
      empty.style.display = 'block';
      track.style.display = 'none';
      if (badge) badge.style.display = 'none';
      console.log('[IVX Reels] 0 published reels — showing empty state');
      return;
    }
    var html = '';
    for (var i = 0; i < reels.length; i++) {
      try {
        var reel = reels[i];
        var title = String(reel.caption || reel.title || projectTitles[String(reel.project_id)] || 'Property Reel');
        var poster = String(reel.thumbnail_url || reel.cover_url || '');
        var safeTitle = title.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
        html += '<div style="min-width:230px;max-width:230px;scroll-snap-align:start;border:1px solid var(--border);border-radius:16px;overflow:hidden;background:var(--bg2);">'
          + '<video src="' + reel.video_url + '"' + (poster ? ' poster="' + poster + '"' : '') + ' controls playsinline preload="metadata" style="width:100%;aspect-ratio:9/16;object-fit:cover;background:#000;display:block;" onerror="this.closest(\'div\').style.display=\'none\';console.log(\'[IVX Reels] Removed broken reel video\')"></video>'
          + '<div style="padding:10px 12px;font-size:13px;font-weight:600;color:var(--text1);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + safeTitle + '</div>'
          + '</div>';
      } catch (itemErr) {
        console.log('[IVX Reels] Skipped one invalid reel:', itemErr && itemErr.message);
      }
    }
    track.innerHTML = html;
    track.style.display = 'flex';
    empty.style.display = 'none';
    if (badge && countEl) { badge.style.display = ''; countEl.textContent = reels.length + (reels.length === 1 ? ' REEL' : ' REELS'); }
    console.log('[IVX Reels] Rendered', reels.length, 'published reels');
  }

  function loadReels() {
    reelsFetch('jv_deals?select=id,title,project_name,published,status').then(function (deals) {
      var publishedIds = [];
      var titles = {};
      for (var i = 0; i < deals.length; i++) {
        var d = deals[i];
        var active = d.published === true || ['active', 'published', 'live'].indexOf(String(d.status || '').toLowerCase()) !== -1;
        if (active) {
          publishedIds.push(String(d.id));
          titles[String(d.id)] = String(d.project_name || d.title || '');
        }
      }
      /* Canonical reels table first (jv_deal_reels, keyed to jv_deals.id);
         fall back to legacy project_videos (approved rows only). */
      return reelsFetch('jv_deal_reels?select=*&published=eq.true&order=sort_order.asc,created_at.desc')
        .catch(function () {
          console.log('[IVX Reels] jv_deal_reels unavailable — falling back to project_videos (approved only)');
          return reelsFetch('project_videos?select=*&is_approved=eq.true&order=is_pinned.desc,created_at.desc');
        })
        .then(function (rows) {
          var seen = {};
          var valid = [];
          for (var ri = 0; ri < (Array.isArray(rows) ? rows.length : 0); ri++) {
            var row = rows[ri];
            if (!isValidReel(row, publishedIds)) continue;
            var fp = normalizeReelFingerprint(row.video_url);
            if (seen[fp]) continue;
            seen[fp] = true;
            valid.push(row);
          }
          renderReels(valid, titles);
        });
    }).catch(function (err) {
